import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How do boat loans work?", a: "Boat loans work like other installment loans: you borrow the purchase amount minus down payment and repay it monthly with interest." },
  { q: "What is a good interest rate for a boat loan?", a: "A good boat loan rate depends on credit, loan size, term, age of the boat, collateral, and market rates." },
  { q: "How long can you finance a boat?", a: "Boat loan terms can range from a few years to 20 years for larger vessels, though longer terms increase total interest." },
  { q: "What credit score do you need for a boat loan?", a: "Requirements vary by lender, but stronger credit usually improves approval odds and lowers the rate." },
  { q: "Is it smart to finance a boat?", a: "Financing can make sense if the payment fits your budget and you account for insurance, storage, fuel, maintenance, and depreciation." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
function payment(principal: number, apr: number, months: number) { const r = apr / 100 / 12; return r === 0 ? principal / months : principal * r / (1 - Math.pow(1 + r, -months)); }

export default function BoatLoanCalculator() {
  useCurrencyVersion();
  const [price, setPrice] = useState(50000);
  const [down, setDown] = useState(5000);
  const [term, setTerm] = useState(120);
  const [rate, setRate] = useState(8);
  const result = useMemo(() => { const principal = Math.max(0, price - down); const monthly = payment(principal, rate, term); return { principal, monthly, interest: monthly * term - principal, total: monthly * term + down }; }, [price, down, term, rate]);
  const prices = [20000, 50000, 100000, 200000, 500000];

  return (
    <>
      <SEOHead title="Free Boat Loan Calculator Online - Calculate Monthly Boat Loan Payments Instantly | CalcHive" description="Free online boat loan calculator. Calculate monthly boat loan payments, total interest and total cost for any boat price, rate and term instantly. 100% free, no signup required." canonical="/boat-loan-calculator" keywords="free boat loan calculator, marine loan calculator free online, boat financing calculator free, calculate boat loan payment free, watercraft loan calculator free online" category="Financial Calculators" breadcrumbName="Free Boat Loan Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Boat Loan Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate marine loan payments, total interest, and total boat financing cost.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Boat price</label><input type="number" value={price} onChange={(e) => setPrice(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Down payment</label><input type="number" value={down} onChange={(e) => setDown(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Loan term months</label><input type="number" value={term} onChange={(e) => setTerm(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Interest rate (%)</label><input type="number" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div></div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Monthly Boat Payment</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.monthly)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Loan amount</p><p className="text-lg font-extrabold text-foreground">{money(result.principal)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total interest</p><p className="text-lg font-extrabold text-foreground">{money(result.interest)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total cost</p><p className="text-lg font-extrabold text-foreground">{money(result.total)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Boat Loan Monthly Payments for Free</h2><p className="text-muted-foreground leading-relaxed">Subtract your down payment from the boat price, then amortize the loan amount over the term at the annual rate.</p><h2 className="text-2xl font-bold text-foreground">How Boat Loan Rates and Terms Affect Your Payment</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Boat Loan Monthly Payment by Price and Term</caption><thead className="bg-muted/60"><tr>{["Boat Price", "8% Rate 10yr", "8% Rate 15yr", "10% Rate 10yr", "10% Rate 15yr"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{prices.map((p) => <tr key={p}><td className="py-2.5 px-3 font-semibold">{money(p, 0)}</td><td className="py-2.5 px-3">{money(payment(p, 8, 120))}</td><td className="py-2.5 px-3">{money(payment(p, 8, 180))}</td><td className="py-2.5 px-3">{money(payment(p, 10, 120))}</td><td className="py-2.5 px-3">{money(payment(p, 10, 180))}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Marine Loan Calculator for Every Boat Buyer</h2><p className="text-muted-foreground leading-relaxed">Remember to budget for fuel, slip fees, storage, registration, insurance, and maintenance alongside the loan payment.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/boat-loan-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


